1	/**
2	 * The block tree model.
3	 *
4	 * Design invariant (design.md D2): nodes own their original lines VERBATIM —
5	 * markers, indentation, trailing whitespace and all. Encoding is pure span
6	 * concatenation, which makes the byte-identity round-trip structural rather
7	 * than aspirational. A "line" is a string without its terminating newline;
8	 * the document is `lines.join('\n')`.
9	 *
10	 * Blank-line ownership: a run of blank lines belongs to the *preceding* node
11	 * as its `trailingGap` (or to the preamble). Segmentation is total: every
12	 * input line lives in exactly one span.
13	 */
14	
15	/** Kinds that participate in the outline structure. */
16	export type StructuralKind = 'heading' | 'paragraph' | 'list-item';
17	
18	/** Leaf atoms: movable as units, internals never parsed as nodes. */
19	export type AtomKind = 'code' | 'table' | 'callout' | 'quote' | 'html' | 'hr';
20	
21	export type NodeKind = StructuralKind | AtomKind;
22	
23	export const ATOM_KINDS: ReadonlySet<NodeKind> = new Set<NodeKind>([
24	  'code',
25	  'table',
26	  'callout',
27	  'quote',
28	  'html',
29	  'hr',
30	]);
31	
32	export type ListStyle =
33	  | { type: 'bullet'; marker: '-' | '*' | '+' }
34	  | { type: 'ordered'; number: number; delimiter: '.' | ')' };
35	
36	export interface OutlineNode {
37	  /** Stable within one tree; not persisted anywhere. */
38	  readonly id: number;
39	  readonly kind: NodeKind;
40	  /** Heading level 1–6. Present iff kind === 'heading'. */
41	  readonly level?: number;
42	  /** Present iff kind === 'heading' and the source used setext underlines. */
43	  readonly setext?: boolean;
44	  /** Present iff kind === 'list-item'. */
45	  readonly listStyle?: ListStyle;
46	  /**
47	   * The node's own lines, verbatim: the heading line (2 lines for setext),
48	   * the paragraph's lines, the list item's marker line plus its continuation
49	   * lines, or the atom's full block.
50	   */
51	  readonly lines: readonly string[];
52	  /** Blank lines that follow this node's lines, verbatim. */
53	  readonly trailingGap: readonly string[];
54	  readonly children: readonly OutlineNode[];
55	}
56	
57	export interface OutlineDoc {
58	  /**
59	   * Inert document preamble: YAML frontmatter plus the blank lines that
60	   * follow it. Never a node, never touched by operations.
61	   */
62	  readonly preamble: readonly string[];
63	  readonly children: readonly OutlineNode[];
64	}
65	
66	let nextId = 1;
67	
68	export function makeNode(
69	  partial: Omit<OutlineNode, 'id' | 'trailingGap' | 'children'> &
70	    Partial<Pick<OutlineNode, 'trailingGap' | 'children'>>,
71	): OutlineNode {
72	  return {
73	    trailingGap: [],
74	    children: [],
75	    ...partial,
76	    id: nextId++,
77	  };
78	}
79	
80	export function isAtom(node: OutlineNode): boolean {
81	  return ATOM_KINDS.has(node.kind);
82	}
83	
84	/** Path from the root to a node: indices into successive `children` arrays. */
85	export type NodePath = readonly number[];
86	
87	export function nodeAt(doc: OutlineDoc, path: NodePath): OutlineNode | undefined {
88	  let list: readonly OutlineNode[] = doc.children;
89	  let node: OutlineNode | undefined;
90	  for (const index of path) {
91	    node = list[index];
92	    if (!node) return undefined;
93	    list = node.children;
94	  }
95	  return node;
96	}
97	
98	export function findPath(doc: OutlineDoc, id: number): NodePath | undefined {
99	  const walk = (nodes: readonly OutlineNode[], prefix: NodePath): NodePath | undefined => {
100	    for (let i = 0; i < nodes.length; i++) {
101	      const node = nodes[i]!;
102	      if (node.id === id) return [...prefix, i];
103	      const found = walk(node.children, [...prefix, i]);
104	      if (found) return found;
105	    }
106	    return undefined;
107	  };
108	  return walk(doc.children, []);
109	}
110	
111	/** Replace the children array at `path`'s parent level via a pure update. */
112	export function updateSiblings(
113	  doc: OutlineDoc,
114	  parentPath: NodePath,
115	  update: (siblings: readonly OutlineNode[]) => readonly OutlineNode[],
116	): OutlineDoc {
117	  const rebuild = (
118	    nodes: readonly OutlineNode[],
119	    depth: number,
120	  ): readonly OutlineNode[] => {
121	    if (depth === parentPath.length) return update(nodes);
122	    const index = parentPath[depth]!;
123	    return nodes.map((node, i) =>
124	      i === index ? { ...node, children: rebuild(node.children, depth + 1) } : node,
125	    );
126	  };
127	  return { ...doc, children: rebuild(doc.children, 0) };
128	}
129	
130	export function* walkNodes(doc: OutlineDoc): Generator<OutlineNode> {
131	  function* walk(nodes: readonly OutlineNode[]): Generator<OutlineNode> {
132	    for (const node of nodes) {
133	      yield node;
134	      yield* walk(node.children);
135	    }
136	  }
137	  yield* walk(doc.children);
138	}
139	
140	/**
141	 * Structural equality ignoring node ids — the comparison used by the
142	 * round-trip and closure property tests.
143	 */
144	export function treesEqual(a: OutlineDoc, b: OutlineDoc): boolean {
145	  const nodeEqual = (x: OutlineNode, y: OutlineNode): boolean =>
146	    x.kind === y.kind &&
147	    x.level === y.level &&
148	    x.setext === y.setext &&
149	    JSON.stringify(x.listStyle ?? null) === JSON.stringify(y.listStyle ?? null) &&
150	    x.lines.length === y.lines.length &&
151	    x.lines.every((line, i) => line === y.lines[i]) &&
152	    x.trailingGap.length === y.trailingGap.length &&
153	    x.trailingGap.every((line, i) => line === y.trailingGap[i]) &&
154	    x.children.length === y.children.length &&
155	    x.children.every((child, i) => nodeEqual(child, y.children[i]!));
156	  return (
157	    a.preamble.length === b.preamble.length &&
158	    a.preamble.every((line, i) => line === b.preamble[i]) &&
159	    a.children.length === b.children.length &&
160	    a.children.every((child, i) => nodeEqual(child, b.children[i]!))
161	  );
162	}
163

