1	import fc from 'fast-check';
2	import type { OutlineDoc, OutlineNode } from '../src/model';
3	import { makeNode } from '../src/model';
4	
5	/** Adversarial markdown text: fragments that stress the segmenter. */
6	export const arbMarkdownText: fc.Arbitrary<string> = fc
7	  .array(
8	    fc.oneof(
9	      { weight: 3, arbitrary: fc.constantFrom('plain text', 'with | pipe', 'trailing spaces  ', '\ttab lead') },
10	      fc.constantFrom('# H1', '## H2', '###### H6', '#nospace', '####### seven'),
11	      fc.constantFrom('- item', '* item', '+ item', '1. one', '12) twelve', '-', '- [ ] task', '- [x] done'),
12	      fc.constantFrom('  - nested', '    - deeper', '   half indent', '  continuation'),
13	      fc.constantFrom('```', '```js', '~~~', 'code inside', '    indented'),
14	      fc.constantFrom('> quote', '> [!note] callout', '> > nested'),
15	      fc.constantFrom('---', '***', '___', '- - -', '===', '=='),
16	      fc.constantFrom('| a | b |', '|---|---|', '| 1 | 2 |'),
17	      fc.constantFrom('<div>', '</div>', '<!-- comment -->'),
18	      fc.constantFrom('', '', '', ' ', '\t'),
19	    ),
20	    { maxLength: 40 },
21	  )
22	  .map((lines) => lines.join('\n'));
23	
24	const arbGap: fc.Arbitrary<string[]> = fc.oneof(
25	  { weight: 3, arbitrary: fc.constant<string[]>(['']) },
26	  fc.constant<string[]>([]),
27	  fc.constant<string[]>(['', '']),
28	  fc.constant<string[]>([' ']),
29	);
30	
31	// Node text must not itself read as a block marker (a paragraph of "-" would
32	// re-parse as an empty list item), so require an alphanumeric first char and
33	// exclude ordered-marker prefixes like "1.".
34	const arbText: fc.Arbitrary<string> = fc
35	  .stringMatching(/^[a-zA-Z0-9][a-zA-Z0-9 .,!?'-]{0,29}$/)
36	  .filter((s) => s.trim().length > 0 && !/^\d+[.)]([ \t]|$)/.test(s.trim()));
37	
38	/**
39	 * Generates trees that are *valid by construction* for the encode→parse
40	 * direction: every node's lines are well-formed for its kind and depth
41	 * context, gaps separate paragraph runs, etc.
42	 */
43	export function arbTree(): fc.Arbitrary<OutlineDoc> {
44	  // List subtree at a given indentation column.
45	  const listItem = (indent: number, depth: number): fc.Arbitrary<OutlineNode> =>
46	    fc
47	      .tuple(
48	        arbText,
49	        depth > 0
50	          ? fc.array(fc.oneof(
51	              { weight: 3, arbitrary: listItem(indent + 2, depth - 1) },
52	              codeAtom(indent + 2),
53	            ), { maxLength: 3 })
54	          : fc.constant([] as OutlineNode[]),
55	        arbGap,
56	      )
57	      .map(([text, children, gap]) =>
58	        makeNode({
59	          kind: 'list-item',
60	          listStyle: { type: 'bullet', marker: '-' },
61	          lines: [`${' '.repeat(indent)}- ${text}`],
62	          trailingGap: children.length > 0 ? [] : gap.filter((g) => g === ''),
63	          children,
64	        }),
65	      );
66	
67	  const codeAtom = (indent: number): fc.Arbitrary<OutlineNode> =>
68	    arbText.map((text) =>
69	      makeNode({
70	        kind: 'code',
71	        lines: [`${' '.repeat(indent)}\`\`\``, `${' '.repeat(indent)}${text}`, `${' '.repeat(indent)}\`\`\``],
72	        trailingGap: [''],
73	      }),
74	    );
75	
76	  const paragraph: fc.Arbitrary<OutlineNode> = fc
77	    .tuple(arbText, fc.array(listItem(0, 2), { maxLength: 3 }))
78	    .map(([text, items]) =>
79	      makeNode({
80	        kind: 'paragraph',
81	        lines: [text],
82	        trailingGap: [''],
83	        children: items,
84	      }),
85	    );
86	
87	  const sectionContent: fc.Arbitrary<OutlineNode[]> = fc
88	    .array(fc.oneof({ weight: 3, arbitrary: paragraph }, listItem(0, 2), codeAtom(0)), {
89	      maxLength: 4,
90	    })
91	    .map(foldListsIntoParagraphs)
92	    .map(normalizeSectionGaps);
93	
94	  const heading = (level: number, depth: number): fc.Arbitrary<OutlineNode> =>
95	    fc
96	      .tuple(
97	        arbText,
98	        sectionContent,
99	        depth > 0
100	          ? fc.array(heading(Math.min(level + 1, 6), depth - 1), { maxLength: 2 })
101	          : fc.constant([] as OutlineNode[]),
102	      )
103	      .map(([text, content, subs]) =>
104	        makeNode({
105	          kind: 'heading',
106	          level,
107	          lines: [`${'#'.repeat(level)} ${text}`],
108	          trailingGap: [''],
109	          children: [...content, ...subs],
110	        }),
111	      );
112	
113	  return fc
114	    .tuple(sectionContent, fc.array(heading(2, 2), { maxLength: 3 }))
115	    .map(([content, sections]) => ({
116	      preamble: [],
117	      children: [...content, ...sections],
118	    }));
119	}
120	
121	/**
122	 * The attachment rule makes \"list item sibling right after a paragraph\"
123	 * unrepresentable — parse always claims it as the paragraph's child. Valid
124	 * trees must respect that, so the generator folds such items in.
125	 */
126	function foldListsIntoParagraphs(nodes: OutlineNode[]): OutlineNode[] {
127	  const out: OutlineNode[] = [];
128	  for (const node of nodes) {
129	    const prev = out[out.length - 1];
130	    if (node.kind === 'list-item' && prev?.kind === 'paragraph') {
131	      out[out.length - 1] = { ...prev, children: [...prev.children, node] };
132	    } else {
133	      out.push(node);
134	    }
135	  }
136	  return out;
137	}
138	
139	/**
140	 * Adjacent paragraphs (and a paragraph directly followed by a sibling list)
141	 * must be separated by a blank line or the parser would merge/attach them —
142	 * generated trees enforce the same separation invariants the ops maintain.
143	 */
144	function normalizeSectionGaps(nodes: OutlineNode[]): OutlineNode[] {
145	  return nodes.map((node, i) => {
146	    const lastLeafGapEmpty = trailingGapOfSubtree(node).length === 0;
147	    if (i < nodes.length - 1 && lastLeafGapEmpty) {
148	      return withLastLeafGap(node, ['']);
149	    }
150	    return node;
151	  });
152	}
153	
154	function trailingGapOfSubtree(node: OutlineNode): readonly string[] {
155	  const last = node.children[node.children.length - 1];
156	  return last ? trailingGapOfSubtree(last) : node.trailingGap;
157	}
158	
159	function withLastLeafGap(node: OutlineNode, gap: string[]): OutlineNode {
160	  const last = node.children[node.children.length - 1];
161	  if (!last) return { ...node, trailingGap: gap };
162	  return {
163	    ...node,
164	    children: [...node.children.slice(0, -1), withLastLeafGap(last, gap)],
165	  };
166	}
