    const fromLine = tr.startState.doc.lineAt(fromA).number - 1;
    const toLine = tr.startState.doc.lineAt(Math.max(fromA, toA - 1)).number - 1;
    spans.push({ fromLine, toLine });
  });
  return spans;
}

