  return { anchor: offsetToLinePos(doc, range.anchor), head: offsetToLinePos(doc, range.head) };
}

function rangeUnchanged(a: LineRange, b: LineRange): boolean {
  return (
    a.anchor.line === b.anchor.line &&
    a.anchor.ch === b.anchor.ch &&
    a.head.line === b.head.line &&
    a.head.ch === b.head.ch
