/** A real double-click at a document position (word selection). */
export async function doubleClickAt(line: number, ch: number): Promise<void> {
  const coords = await posToCoords(line, ch);
  const x = Math.round(coords.left);
  const y = Math.round((coords.top + coords.bottom) / 2);
  await browser
    .action('pointer', { parameters: { pointerType: 'mouse' } })
    .move({ x, y, origin: 'viewport' })
    .down({ button: 0 })
    .up({ button: 0 })
    .pause(10)
    .down({ button: 0 })
    .up({ button: 0 })
    .perform();
}

/**
 * Add a second selection range via a held-modifier drag (Cmd/Ctrl+drag —
 * CM6's default "add a selection range" gesture). The modifier is held
 * across two separate `perform()` calls (`perform(true)` skips the
 * automatic release), spanning the drag in between, per the W3C Actions
 * spec: input state persists across `performActions` calls in a session
 * until explicitly released.
 */
export async function modifierDragSelect(
  from: { line: number; ch: number },
  to: { line: number; ch: number },
): Promise<void> {
  await browser.action('key').down(PRIMARY_MOD).perform(true);
  try {
    await mouseDragSelect(from, to, 2);
  } finally {
    await browser.action('key').up(PRIMARY_MOD).perform();
  }
}

