/**
 * Viewport pixel coordinates of a document position, via CM6's own
 * `coordsAtPos` — precise per-character placement, unlike approximating
 * from a `.cm-line`'s bounding rect. On a large (virtualized) document the
 * target position may not currently be rendered — `coordsAtPos` returns
 * null for anything outside CM6's render window — so this scrolls the
 * position into view first via `EditorView.scrollIntoView` (a StateEffect,
 * dispatched through the instance's own constructor since that's the only
 * reference to the `EditorView` class available in this browser-context
 * script) BEFORE measuring. That dispatch touches scroll position only,
 * never the selection/cursor — no side effect on what's being tested.
 */
export function posToCoords(
  line: number,
  ch: number,
): Promise<{ left: number; top: number; bottom: number }> {
  return browser.executeObsidian(
    ({ app, obsidian }, line, ch) => {
      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
      if (!view) throw new Error('no active markdown view');
      const cm = (view.editor as any).cm;
      const pos = cm.state.doc.line(line + 1).from + ch;
      if (!cm.coordsAtPos(pos)) {
        cm.dispatch({ effects: (cm.constructor as any).scrollIntoView(pos, { y: 'center' }) });
      }
      const coords = cm.coordsAtPos(pos);
      if (!coords) throw new Error(`no coords at line ${line} ch ${ch}`);
      return { left: coords.left, top: coords.top, bottom: coords.bottom };
    },
    line,
    ch,
  );
}

