/**
 * Add a second selection RANGE alongside the current selection: Cmd/Ctrl+
 * click adds an empty cursor at `from` without disturbing the existing
 * selection, then Shift+click at `to` extends that newest cursor into a
 * range — CM6's standard two-step multi-range gesture (a single held-
 * modifier drag adds a cursor but does not reliably extend it to a range
 * across separate `performActions` calls in this harness). Each modifier
 * is held via `perform(true)` (skips the automatic release) spanning the
 * click that needs it, per the W3C Actions spec: input state persists
 * across `performActions` calls in a session until explicitly released.
 */
export async function addSelectionRange(
  from: { line: number; ch: number },
  to: { line: number; ch: number },
): Promise<void> {
  const fromCoords = await posToCoords(from.line, from.ch);
  const toCoords = await posToCoords(to.line, to.ch);
  const click = async (x: number, y: number): Promise<void> => {
    await browser
      .action('pointer', { parameters: { pointerType: 'mouse' } })
      .move({ x, y, origin: 'viewport' })
      .down({ button: 0 })
      .up({ button: 0 })
      .perform();
  };

  await browser.action('key').down(PRIMARY_MOD).perform(true);
  try {
    await click(Math.round(fromCoords.left), Math.round((fromCoords.top + fromCoords.bottom) / 2));
  } finally {
    await browser.action('key').up(PRIMARY_MOD).perform();
  }

  await browser.action('key').down(Key.Shift).perform(true);
  try {
    await click(Math.round(toCoords.left), Math.round((toCoords.top + toCoords.bottom) / 2));
  } finally {
    await browser.action('key').up(Key.Shift).perform();
  }
}

