/**
 * Throwaway live verification for the dev-vault hot-reload plugin — NOT a
 * permanent regression test for true-outliner itself, deleted after use.
 */

import { browser, expect } from '@wdio/globals';
import { obsidianPage } from 'wdio-obsidian-service';
import * as fsp from 'node:fs/promises';
import * as h from '../helpers.js';

describe('hot-reload dev plugin (throwaway check)', function () {
  before(async function () {
    await obsidianPage.resetVault();
  });

  it('editing main.js on disk triggers an automatic disable+enable', async function () {
    const loaded = await browser.executeObsidian(({ plugins }) => Boolean(plugins.trueOutliner));
    expect(loaded).toBe(true);

    const mainJsPath = h.vaultFilePath('.obsidian/plugins/true-outliner/main.js');
    const original = await fsp.readFile(mainJsPath, 'utf-8');
    // Rewrite with identical bytes plus a trailing comment — a real write,
    // content genuinely differs so this isn't a no-op fs event.
    await fsp.writeFile(mainJsPath, original + '\n// hotreload-check-marker\n');

    await browser.waitUntil(
      async () => (await h.noticeTexts()).some((t) => t.includes('Hot-reloaded: true-outliner')),
      { timeout: 5000, timeoutMsg: 'no hot-reload notice appeared after editing main.js' },
    );

    // The plugin instance must be a genuinely NEW one post-reload, not just
    // still running — confirm it's still fully functional (command present).
    expect(await h.commandRegistered('toggle-outline-mode')).toBe(true);

    await fsp.writeFile(mainJsPath, original); // restore
  });
});

