it('multi-range selection: each range escalates independently', async function () {
  const md = 'One.\n\nTwo.\n\nThree.\n\nFour.\n';
  await outlineNote(md);
  // Range 1: within "One." (must stay native). Range 2: crosses the
  // "Three."/"Four." boundary (must escalate on its own). Dispatched as
  // one real `select`-annotated transaction — see dispatchSelectOnlyRanges's
  // doc comment for why this replaces a simulated add-range gesture here.
  await h.dispatchSelectOnlyRanges([
    { anchor: { line: 0, ch: 1 }, head: { line: 0, ch: 3 } },
    { anchor: { line: 4, ch: 2 }, head: { line: 6, ch: 2 } },
  ]);

  const ranges = await browser.executeObsidian(({ app, obsidian }) => {
    const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView)!;
    const cm = (view.editor as any).cm;
    const doc = cm.state.doc;
    const toPos = (offset: number) => {
      const line = doc.lineAt(offset);
      return { line: line.number - 1, ch: offset - line.from };
    };
    return cm.state.selection.ranges.map((r: { anchor: number; head: number }) => ({
      anchor: toPos(r.anchor),
      head: toPos(r.head),
    }));
  });

  expect(ranges.length).toBe(2);
  const withinRange = ranges.find((r: any) => r.anchor.line === 0 || r.head.line === 0);
  const escalatedRange = ranges.find((r: any) => r.anchor.line === 4 || r.head.line === 4);
  expect(withinRange).toBeDefined();
  expect(withinRange.anchor).toEqual({ line: 0, ch: 1 });
  expect(withinRange.head).toEqual({ line: 0, ch: 3 });
  expect(escalatedRange).toBeDefined();
  expect(escalatedRange.anchor).toEqual({ line: 4, ch: 0 });
  expect(escalatedRange.head).toEqual({ line: 6, ch: 'Four.'.length });
});

